    <style>
        .serviceCard {
            width: 100%;
            /* height: 50vh; */
            background-color: white;
            position: relative;
            overflow: hidden;
            box-shadow: rgba(0, 0, 0, 0.16) 0px 1px 4px;
            display: flex;
            flex-direction: column;
            align-items: center;
            border-radius: 10px;
        }

        .serviceCard img {
            /* position: absolute; */
            top: 0%;
            /* left: 50%; */
            /* transform: translate(-50%); */
            width: 35%;
            justify-self: center;
            padding: 15px;
            margin: 10px;
            /* background-color: #F18142;
            border-radius: 50%; */
        }

        .serviceCard .serviceCardinner {
            text-align: center;
            /* position: absolute; */
            left: 0%;
            /* bottom: 0%; */
            /* top: 33.3vh; */
            padding: 10px 15px;
            /* height: 30vh; */
            /* background-color: rgba(0, 0, 0, 0.418); */
            backdrop-filter: blur(5px);
            width: 100%;
            transition: 0.5s ease-in-out;
        }

        .serviceCard .serviceCardinner h6 {
            /* color: white; */
            text-shadow: 1px 1px 1px black;
            font-style: italic;
            transition: 0.5s ease-in-out;
        }

        .serviceCard .serviceCardinner p {
            font-size: 15px;
            /* color: white; */
            line-height: 20px;
            font-style: italic;
            height: 17vh;
            max-height: 17vh;
            overflow: auto;
        }

        .serviceCard .serviceCardinner a span {
            display: flex;
            align-items: center;
            justify-content: flex-start;
        }

        .serviceCard .serviceCardinner .view-btn svg {
            fill: white;
            margin-top: 5px;
        }
    </style>






